class Solution:
    def maximumOddBinaryNumber(self, s):
        chars = sorted(s, reverse=True)
        ones_count = chars.count('1')
        last_one_pos = ones_count - 1
        moved = chars.pop(last_one_pos)
        chars.append(moved)
        return ''.join(chars)

solutions.python:
class Solution:
    def maximumOddBinaryNumber(self, s):
        ones = s.count('1')
        zeros = len(s) - ones
        return '1' * (ones - 1) + '0' * zeros + '1'

